#include <stdio.h>
#include <stdlib.h>
#define MAX_SIZE 100

typedef struct Set {
    int items[MAX_SIZE];
    int size;
} Set;

void initSet(Set* set) {
    set->size = 0;
}

void add(Set* set, int item) {
    for (int i = 0; i < set->size; i++) {
        if (set->items[i] == item) return;
    }
    if (set->size < MAX_SIZE) {
        set->items[set->size++] = item;
    }
}

int removeItem(Set* set, int item) {
    for (int i = 0; i < set->size; i++) {
        if (set->items[i] == item) {
            set->items[i] = set->items[--set->size];
            return 1;
        }
    }
    return 0;
}

int contains(Set* set, int item) {
    for (int i = 0; i < set->size; i++) {
        if (set->items[i] == item) return 1;
    }
    return 0;
}

void printSet(Set* set) {
    printf("[");
    for (int i = 0; i < set->size; i++) {
        printf("%d", set->items[i]);
        if (i < set->size - 1) printf(", ");
    }
    printf("]\n");
}

int main() {
    Set set;
    initSet(&set);
    int values[] = {5, 10, 15};
    for (int i = 0; i < 3; i++) {
        add(&set, values[i]);
    }
    printf("Set after add: ");
    printSet(&set);
    removeItem(&set, 10);
    printf("Set after remove: ");
    printSet(&set);
    printf("Contains 5: %d\n", contains(&set, 5));
    return 0;
}
// Output: Set after add: [5, 10, 15]
// Output: Set after remove: [5, 15]
// Output: Contains 5: 1

