#include <iostream> 
 #include <vector>
#include <algorithm>

class Set {
 private:
 std::vector<int> items;

public:
    void add(int item) {
        if (!contains(item)) {
            items.push_back(item);
        }
    }

    bool remove(int item) {
        auto it = std::find(items.begin(), items.end(), item);
        if (it != items.end()) {
            items.erase(it);
            return true;
        }
        return false;
    }

    bool contains(int item) {
        return std::find(items.begin(), items.end(), item) != items.end();
    }

    std::vector<int> toVector() {
        return items;
    }
};

int main() {
    Set s;
    int values[] = {5, 10, 15};
    for (int val : values) {
        s.add(val);
    }
    std::cout << "Set after add: [";
    auto result = s.toVector();
    for (size_t i = 0; i < result.size(); i++) {
        std::cout << result[i];
        if (i < result.size() - 1) std::cout << ", ";
    }
    std::cout << "]\n";
    s.remove(10);
    std::cout << "Set after remove: [";
    result = s.toVector();
    for (size_t i = 0; i < result.size(); i++) {
        std::cout << result[i];
        if (i < result.size() - 1) std::cout << ", ";
    }
    std::cout << "]\n";
    std::cout << "Contains 5: " << (s.contains(5) ? "true" : "false") << "\n";
    return 0;
}
